mapper.select:
select w.id, w.name, w.course_id, c.name as courseName,
sc.student_id, s.name as studentName, s.clazz,
sc.score, sc.position, sc.work_status
from work w
join score sc on sc.work_id = w.id
and sc.work_status = #{workStatus}
and sc.student_id = #{studentId}
left join course c on w.course_id = c.id
left join student s on sc.student_id = s.student_id

    and w.id = #{id}
    and w.name like concat('%', #{name}, '%')
    and w.course_id = #{courseId}
    and c.teacher_id = #{teacherId}

order by w.id desc

select c.id as courseId,c.name as courseName,w.id,w.name
from course c
right join work w on w.course_id=c.id

    and w.id = #{id}
    and w.name like concat('%', #{name}, '%')
    and w.course_id = #{courseId}
    and c.teacher_id=#{teacherId}

order by w.id desc

select w.id,w.name,w.course_id,c.name as courseName,t.name as teacherName
from work w
left join course c on w.course_id = c.id
left join credit c2 on c2.course_id=w.course_id
left join teacher t on t.teacher_id=c.teacher_id

    and c2.student_id=#{studentId}
    and w.id=#{id}
    and w.name=#{name}
 and w.course_id=#{courseId}
and c.name=#{courseName}

select s.work_id as id,w.name,w.course_id,c.name as courseName,
       t.name as teacherName,s.score,s.work_status
from score s
left join work w on w.id=s.work_id
left join course c on w.course_id=c.id
left join teacher t on c.teacher_id=t.teacher_id
    
        and s.student_id=#{studentId}
        and w.id=#{id}
        and w.name=#{name}
         and w.course_id=#{courseId}
        and c.name=#{courseName}
        and s.work_status=#{workStatus}
